using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments =
    [
        new() { Id = 1, Name = "Computer Science", Code = "CS" },
        new() { Id = 2, Name = "Mathematics", Code = "MATH" },
        new() { Id = 3, Name = "Physics", Code = "PHYS" },
        new() { Id = 4, Name = "English", Code = "ENG" },
        new() { Id = 5, Name = "History", Code = "HIST" },
    ];

    private readonly List<Course> _courses =
    [
        new() { Id = 1, Code = "CS 101", Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using C#. Topics include variables, control flow, functions, and object-oriented design.", Credits = 3, Schedule = "MWF 9:00–9:50 AM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of experience teaching introductory computer science. She holds a PhD from MIT and has published extensively on CS pedagogy.", DepartmentId = 1, IsFeatured = true },
        new() { Id = 2, Code = "CS 201", Title = "Data Structures & Algorithms", Description = "Study of fundamental data structures (arrays, linked lists, trees, graphs) and algorithm design techniques including sorting, searching, and dynamic programming.", Credits = 4, Schedule = "TTh 10:30–11:50 AM", InstructorName = "Dr. James Rivera", InstructorBio = "Dr. Rivera specializes in algorithm optimization and competitive programming. He previously worked at Google Research.", DepartmentId = 1, IsFeatured = true },
        new() { Id = 3, Code = "CS 310", Title = "Database Systems", Description = "Relational database design, SQL, normalization, transaction processing, and introduction to NoSQL databases.", Credits = 3, Schedule = "MWF 1:00–1:50 PM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of experience teaching introductory computer science. She holds a PhD from MIT and has published extensively on CS pedagogy.", DepartmentId = 1 },
        new() { Id = 4, Code = "MATH 151", Title = "Calculus I", Description = "Limits, derivatives, and integrals of single-variable functions with applications to physics and engineering.", Credits = 4, Schedule = "MWF 8:00–8:50 AM", InstructorName = "Prof. Alan Goldberg", InstructorBio = "Prof. Goldberg is an award-winning educator who has taught calculus for over 20 years. He authored the textbook 'Calculus Made Clear'.", DepartmentId = 2, IsFeatured = true },
        new() { Id = 5, Code = "MATH 250", Title = "Linear Algebra", Description = "Vector spaces, matrices, linear transformations, eigenvalues and eigenvectors, and applications.", Credits = 3, Schedule = "TTh 2:00–3:20 PM", InstructorName = "Dr. Maria Lopez", InstructorBio = "Dr. Lopez researches applied linear algebra and numerical methods. She consults for aerospace engineering firms.", DepartmentId = 2 },
        new() { Id = 6, Code = "PHYS 101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Includes weekly lab sessions with hands-on experiments.", Credits = 4, Schedule = "MWF 10:00–10:50 AM + Lab Thu 2:00–4:50 PM", InstructorName = "Dr. Robert Tanaka", InstructorBio = "Dr. Tanaka is an experimental physicist whose research focuses on condensed matter. He brings real-world lab experience into the classroom.", DepartmentId = 3 },
        new() { Id = 7, Code = "PHYS 220", Title = "Electromagnetism", Description = "Electric and magnetic fields, Maxwell's equations, electromagnetic waves, and optics.", Credits = 4, Schedule = "TTh 9:00–10:20 AM", InstructorName = "Dr. Robert Tanaka", InstructorBio = "Dr. Tanaka is an experimental physicist whose research focuses on condensed matter. He brings real-world lab experience into the classroom.", DepartmentId = 3 },
        new() { Id = 8, Code = "ENG 110", Title = "College Writing", Description = "Develop skills in critical reading, argumentative writing, and research. Focus on clear, persuasive academic prose.", Credits = 3, Schedule = "MWF 11:00–11:50 AM", InstructorName = "Prof. Diana Okafor", InstructorBio = "Prof. Okafor is a published author and writing coach. She has mentored hundreds of students in academic and creative writing.", DepartmentId = 4, IsFeatured = true },
        new() { Id = 9, Code = "ENG 240", Title = "American Literature", Description = "Survey of American literary movements from colonial times to the present, including major works of fiction, poetry, and drama.", Credits = 3, Schedule = "TTh 1:00–2:20 PM", InstructorName = "Dr. Kevin Park", InstructorBio = "Dr. Park specializes in 20th-century American fiction. His recent book explores themes of identity in post-war novels.", DepartmentId = 4 },
        new() { Id = 10, Code = "HIST 101", Title = "World History to 1500", Description = "Survey of major civilizations, empires, and cultural exchanges from antiquity through the late medieval period.", Credits = 3, Schedule = "MWF 2:00–2:50 PM", InstructorName = "Dr. Fatima Al-Rashid", InstructorBio = "Dr. Al-Rashid is an archaeologist and historian specializing in ancient Mediterranean and Middle Eastern cultures.", DepartmentId = 5 },
