@page "/"
@inject UniversityCourseCatalog.Services.CatalogService CatalogService

<PageTitle>University Course Catalog</PageTitle>

<div class="hero">
    <h1>University Course Catalog</h1>
    <p>Explore our departments and find the courses that fit your academic goals.</p>
    <a href="/courses" class="btn-primary">Browse All Courses</a>
</div>

<section class="featured-section">
    <h2>Featured Courses</h2>
    <div class="course-grid">
        @foreach (var course in featuredCourses)
        {
            <div class="course-card">
                <span class="course-code">@course.Code</span>
                <h3><a href="/courses/@course.Id">@course.Title</a></h3>
                <p>@course.Credits credits &bull; @course.InstructorName</p>
            </div>
        }
    </div>
</section>

<section class="departments-section">
    <h2>Departments</h2>
    <div class="dept-grid">
        @foreach (var dept in departments)
        {
            <a href="/courses?departmentId=@dept.Id" class="dept-link">@dept.Name</a>
        }
    </div>
</section>

@code {
    private List<UniversityCourseCatalog.Models.Course> featuredCourses = [];
    private List<UniversityCourseCatalog.Models.Department> departments = [];

    protected override void OnInitialized()
    {
        featuredCourses = CatalogService.GetFeaturedCourses();
        departments = CatalogService.GetDepartments();
    }
}

@page "/courses"
@inject UniversityCourseCatalog.Services.CatalogService CatalogService

<PageTitle>Courses - University Course Catalog</PageTitle>

<h1>Course Catalog</h1>

<form method="get" class="filter-form">
    <input type="text" name="search" value="@Search" placeholder="Search by title, code, or instructor…" />
    <select name="departmentId">
        <option value="">All Departments</option>
        @foreach (var dept in departments)
        {
            <option value="@dept.Id" selected="@(DepartmentId == dept.Id)">@dept.Name</option>
        }
    </select>
    <button type="submit" class="btn-primary">Search</button>
</form>

@if (courses.Count == 0)
{
    <p class="no-results">No courses found matching your criteria.</p>
}
else
{
    <div class="course-list">
        @foreach (var course in courses)
        {
            <div class="course-card">
                <span class="course-code">@course.Code</span>
                <h3><a href="/courses/@course.Id">@course.Title</a></h3>
                <p>@course.Credits credits &bull; @course.Schedule</p>
                <p class="instructor">Instructor: @course.InstructorName</p>
            </div>
        }
    </div>
}

@code {
    [SupplyParameterFromQuery] public string? Search { get; set; }
    [SupplyParameterFromQuery] public int? DepartmentId { get; set; }

    private List<UniversityCourseCatalog.Models.Course> courses = [];
    private List<UniversityCourseCatalog.Models.Department> departments = [];

    protected override void OnInitialized()
    {
        departments = CatalogService.GetDepartments();
        courses = CatalogService.GetCourses(Search, DepartmentId);
    }
}

@page "/courses/{Id:int}"
@inject UniversityCourseCatalog.Services.CatalogService CatalogService

@if (course is null)
{
    <PageTitle>Course Not Found</PageTitle>
    <h1>Course Not Found</h1>
    <p>The requested course does not exist. <a href="/courses">Back to catalog</a></p>
}
else
{
    <PageTitle>@course.Title - University Course Catalog</PageTitle>

    <nav class="breadcrumb">
        <a href="/">Home</a> &rsaquo; <a href="/courses">Courses</a> &rsaquo; @course.Code
    </nav>

    <article class="course-detail">
        <header>
            <span class="course-code">@course.Code</span>
            <h1>@course.Title</h1>
        </header>

        <div class="detail-grid">
            <section class="detail-main">
                <h2>Description</h2>
                <p>@course.Description</p>

                <h2>Instructor</h2>
                <h3>@course.InstructorName</h3>
                <p>@course.InstructorBio</p>
            </section>

            <aside class="detail-sidebar">
                <dl>
                    <dt>Credits</dt>
                    <dd>@course.Credits</dd>
                    <dt>Schedule</dt>
                    <dd>@course.Schedule</dd>
                    <dt>Department</dt>
                    <dd>@(department?.Name ?? "Unknown")</dd>
                </dl>
                <a href="/enroll?courseId=@course.Id" class="btn-primary">Request Enrollment</a>
            </aside>
        </div>
    </article>
}

@code {
    [Parameter] public int Id { get; set; }

    private UniversityCourseCatalog.Models.Course? course;
    private UniversityCourseCatalog.Models.Department? department;

    protected override void OnInitialized()
    {
        course = CatalogService.GetCourse(Id);
        if (course is not null)
            department = CatalogService.GetDepartment(course.DepartmentId);
    }
}

@page "/enroll"
@inject UniversityCourseCatalog.Services.CatalogService CatalogService

<PageTitle>Enrollment Request - University Course Catalog</PageTitle>

<h1>Enrollment Request</h1>

@if (Submitted)
{
    <div class="success-message">
        <h2>Request Submitted!</h2>
        <p>Thank you, <strong>@Model.Name</strong>. Your enrollment request for <strong>@(selectedCourse?.Title ?? "the selected course")</strong> has been received. You will be notified by email once processed.</p>
        <a href="/courses">Back to Course Catalog</a>
    </div>
}
else
{
    <EditForm method="post" Model="Model" OnValidSubmit="HandleSubmit" FormName="enrollment" Enhance>
        <DataAnnotationsValidator />
        <AntiforgeryToken />

        <div class="form-group">
            <label for="name">Full Name</label>
            <InputText id="name" @bind-Value="Model.Name" />
            <ValidationMessage For="() => Model.Name" />
        </div>

        <div class="form-group">
            <label for="studentId">Student ID</label>
            <InputText id="studentId" @bind-Value="Model.StudentId" placeholder="e.g. ABC12345" />
            <ValidationMessage For="() => Model.StudentId" />
        </div>

        <div class="form-group">
            <label for="courseId">Course</label>
            <InputSelect id="courseId" @bind-Value="Model.CourseId">
                <option value="0">— Select a course —</option>
                @foreach (var course in courses)
                {
                    <option value="@course.Id">@course.Code – @course.Title</option>
                }
            </InputSelect>
            <ValidationMessage For="() => Model.CourseId" />
        </div>

        <button type="submit" class="btn-primary">Submit Request</button>
    </EditForm>
}

@code {
    [SupplyParameterFromForm] private UniversityCourseCatalog.Models.EnrollmentRequest Model { get; set; } = new();
    [SupplyParameterFromQuery] public int? CourseId { get; set; }

    private List<UniversityCourseCatalog.Models.Course> courses = [];
    private UniversityCourseCatalog.Models.Course? selectedCourse;
    private bool Submitted;

    protected override void OnInitialized()
    {
        courses = CatalogService.GetCourses();

        if (CourseId.HasValue && Model.CourseId == 0)
            Model.CourseId = CourseId.Value;
    }

    private void HandleSubmit()
    {
        selectedCourse = CatalogService.GetCourse(Model.CourseId);
        Submitted = true;
    }
}

