arguments.new_str:
html, body {
    font-family: 'Helvetica Neue', Helvetica, Arial, sans-serif;
    margin: 0;
    padding: 0;
    color: #333;
    line-height: 1.6;
}

a {
    color: #1b6ec2;
    text-decoration: none;
}

a:hover {
    text-decoration: underline;
}

/* Header */
.site-header {
    background: #1b3a5c;
    color: white;
    padding: 0.75rem 2rem;
}

.site-header nav {
    display: flex;
    align-items: center;
    gap: 2rem;
    max-width: 1200px;
    margin: 0 auto;
}

.site-header .brand {
    color: white;
    font-size: 1.25rem;
    font-weight: bold;
    text-decoration: none;
}

.site-header ul {
    list-style: none;
    display: flex;
    gap: 1.5rem;
    margin: 0;
    padding: 0;
}

.site-header ul a {
    color: #cde;
}

.site-header ul a:hover {
    color: white;
}

/* Container */
.container {
    max-width: 1200px;
    margin: 0 auto;
    padding: 2rem;
}

/* Hero */
.hero {
    background: linear-gradient(135deg, #1b3a5c, #2d6da3);
    color: white;
    padding: 3rem 2rem;
    border-radius: 8px;
    text-align: center;
    margin-bottom: 2rem;
}

.hero h1 {
    margin: 0 0 0.5rem;
    font-size: 2.2rem;
}

.hero p {
    margin: 0 0 1.5rem;
    font-size: 1.1rem;
    opacity: 0.9;
}

/* Buttons */
.btn-primary {
    display: inline-block;
    background: #e8a838;
    color: #1b3a5c;
    font-weight: bold;
    padding: 0.6rem 1.5rem;
    border: none;
    border-radius: 4px;
    cursor: pointer;
    text-decoration: none;
    font-size: 1rem;
}

.btn-primary:hover {
    background: #d4952e;
    text-decoration: none;
}

/* Course grid */
.course-grid, .course-list {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));
    gap: 1.5rem;
    margin-top: 1rem;
}

.course-card {
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    padding: 1.25rem;
    background: #fafafa;
    transition: box-shadow 0.2s;
}

.course-card:hover {
    box-shadow: 0 2px 12px rgba(0,0,0,0.1);
}

.course-card h3 {
    margin: 0.5rem 0 0.3rem;
    font-size: 1.1rem;
}

.course-card p {
    margin: 0.25rem 0;
    font-size: 0.9rem;
    color: #555;
}

.course-code {
    display: inline-block;
    background: #1b3a5c;
    color: white;
    padding: 0.15rem 0.5rem;
    border-radius: 3px;
    font-size: 0.8rem;
    font-weight: bold;
}

.instructor {
    font-style: italic;
}

/* Department grid */
.dept-grid {
    display: flex;
    flex-wrap: wrap;
    gap: 1rem;
    margin-top: 1rem;
}

.dept-link {
    display: block;
    background: #f0f4f8;
    border: 1px solid #d0dce8;
    padding: 0.75rem 1.5rem;
    border-radius: 6px;
    font-weight: 500;
}

.dept-link:hover {
    background: #dce8f3;
    text-decoration: none;
}

/* Sections */
.featured-section, .departments-section {
    margin-bottom: 2.5rem;
}

.featured-section h2, .departments-section h2 {
    border-bottom: 2px solid #e8a838;
    padding-bottom: 0.3rem;
    display: inline-block;
}

/* Filter form */
.filter-form {
    display: flex;
    flex-wrap: wrap;
    gap: 0.75rem;
    margin-bottom: 2rem;
    align-items: center;
}

.filter-form input[type="text"] {
    flex: 1;
    min-width: 200px;
    padding: 0.5rem 0.75rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    font-size: 1rem;
}

.filter-form select {
    padding: 0.5rem 0.75rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    font-size: 1rem;
}

.no-results {
    padding: 2rem;
    text-align: center;
    color: #666;
    font-style: italic;
}

/* Course detail */
.breadcrumb {
    margin-bottom: 1.5rem;
    font-size: 0.9rem;
    color: #666;
}

.course-detail header {
    margin-bottom: 1.5rem;
}

.course-detail h1 {
    margin: 0.5rem 0 0;
    font-size: 1.8rem;
}

.detail-grid {
    display: grid;
    grid-template-columns: 1fr 300px;
    gap: 2rem;
}

@media (max-width: 768px) {
    .detail-grid {
        grid-template-columns: 1fr;
    }
}

.detail-main h2 {
    color: #1b3a5c;
    font-size: 1.2rem;
    margin-top: 1.5rem;
}

.detail-sidebar {
    background: #f5f7fa;
    padding: 1.5rem;
    border-radius: 8px;
    border: 1px solid #e0e0e0;
    align-self: start;
}

.detail-sidebar dl {
    margin: 0 0 1.5rem;
}

.detail-sidebar dt {
    font-weight: bold;
    color: #1b3a5c;
    margin-top: 0.75rem;
}

.detail-sidebar dd {
    margin: 0.25rem 0 0;
}

/* Forms */
.form-group {
    margin-bottom: 1.25rem;
}

.form-group label {
    display: block;
    font-weight: 600;
    margin-bottom: 0.3rem;
}

.form-group input, .form-group select {
    width: 100%;
    max-width: 400px;
    padding: 0.5rem 0.75rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    font-size: 1rem;
}

.validation-message {
    color: #c0392b;
    font-size: 0.85rem;
    margin-top: 0.25rem;
}

.success-message {
    background: #d4edda;
    border: 1px solid #c3e6cb;
    padding: 1.5rem;
    border-radius: 8px;
}

.success-message h2 {
    color: #155724;
    margin-top: 0;
}

/* Footer */
.site-footer {
    background: #f5f5f5;
    border-top: 1px solid #ddd;
    text-align: center;
    padding: 1rem 2rem;
    margin-top: 3rem;
    color: #666;
    font-size: 0.9rem;
}

/* Blazor error boundary */
.blazor-error-boundary {
    background: url(data:image/svg+xml;base64,) no-repeat 1rem/1.8rem, #b32121;
    padding: 1rem 1rem 1rem 3.7rem;
    color: white;
}

.blazor-error-boundary::after {
    content: "An error has occurred."
}

